const input = $input.first().json;
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const dateFolder = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const timeSlug = `${pad(now.getHours())}${pad(now.getMinutes())}`;
const agentSlug = String(input.agent || 'unknown').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

const vaultPath = $vars.VAULT_PATH || 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const folder = `${vaultPath}/JobFilter/Agent Runs/${dateFolder}`;
const fileName = `${agentSlug}-${timeSlug}.md`;
const filePath = `${folder}/${fileName}`;

const counts = input.counts || {};
const countsLine = Object.keys(counts).length ? `counts: ${JSON.stringify(counts)}` : '';

const frontmatter = [
  '---',
  'type: agent-run',
  `agent: ${input.agent || 'unknown'}`,
  `run_at: ${now.toISOString()}`,
  `trigger: ${input.trigger || 'cron'}`,
  `status: ${input.status || 'success'}`,
  countsLine,
  `tags: [jobfilter, agent-run, ${agentSlug}]`,
  '---'
].filter(Boolean).join('\n');

const actionsBlock = (input.actions && input.actions.length)
  ? `\n## Actions taken\n${input.actions.map(a => `- ${a}`).join('\n')}\n`
  : '';

const payloadJson = JSON.stringify(input.payload || {}, null, 2);
const md = `${frontmatter}\n\n# ${input.agent || 'Agent'} — ${dateFolder} ${pad(now.getHours())}:${pad(now.getMinutes())}\n\n## Summary\n${input.summary || '(no summary provided)'}\n${actionsBlock}\n## Raw payload\n\n\`\`\`json\n${payloadJson}\n\`\`\`\n`;

return [{
  json: { filePath, fileName, folder, content: md, agent: input.agent, dateFolder, timeSlug },
  binary: {
    data: {
      data: Buffer.from(md, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName,
      fileExtension: 'md'
    }
  }
}];
